# Solution
def check_palindrome(s):
    t = s[::-1]
    if s == t:
        return True
    else:
        return False

def main():
    test_cases = int(input())
    while test_cases > 0:
        s = input()
        if check_palindrome(s) == True:
            print("YES")
        else:
            print("NO")

        test_cases -= 1

main()
